css:
/* ========== 先导篇：字体导入 ========== */
@import url("https://fontsapi.zeoseven.com/871/main/result.css");

body {
    font-family: "ChillHuoFangSong", sans-serif;
    font-weight: normal;
    font-style: normal;
}

/* 定义全局弹出面板主色调 */
.drawer-content {
  background:white;
  border: 1px solid rgba(74, 144, 226, 0.3);
  backdrop-filter: blur(10px);
  box-shadow: 0 8px 32px rgba(44, 95, 127, 0.2);
  border-radius: 0;
}

#table_drawer_content {
  background: white;
  border: 1px solid rgba(74, 144, 226, 0.3);
  backdrop-filter: blur(10px);
  border-radius: 0;
}

.options-content {
  background: linear-gradient(135deg, rgba(232, 244, 248, 0.95), rgba(184, 216, 232, 0.95));
  border: 1px solid rgba(74, 144, 226, 0.3);
  backdrop-filter: blur(10px);
  border-radius: 0;
}

/* ========== 二、顶栏 ========== */
#top-settings-holder {
  background-color: #fff !important;
  border-bottom: 2px dashed #98b7e880;
  box-shadow: none !important;
  padding: 8px 12px !important;
}

#top-bar {
  background-color: transparent !important;
  box-shadow: none !important;
  border: none !important;
}

#top-settings-holder .drawer-icon::before {
  content: '' !important;
  visibility: hidden;
}

#top-settings-holder .drawer {
  flex: 1;
}

#top-settings-holder .drawer-icon {
  display: block;
  margin: 0 auto;
  background-size: contain;
  background-position: center;
  background-repeat: no-repeat;
  transition: all 0.2s ease;
  width:30px;
  height: 30px;
  opacity: 1 !important;
}

.drawer-icon.fa-fw:hover {
  transform: scale(1.08);
  opacity: 0.6;
}

/* 10个顶栏图标 */
#ai-config-button .drawer-icon {
  background-image: url('https://pic1.imgdb.cn/item/691444cb3203f7be00f8bffa.png') !important;
}

#sys-settings-button .drawer-icon {
  background-image: url('https://pic1.imgdb.cn/item/691445923203f7be00f8c5f7.png') !important;
}

#advanced-formatting-button .drawer-icon {
  background-image: url('https://pic1.imgdb.cn/item/691444cb3203f7be00f8bffa.png') !important;
}

#WI-SP-button .drawer-icon {
  background-image: url('https://pic1.imgdb.cn/item/691445923203f7be00f8c5f7.png') !important;
}

#user-settings-button .drawer-icon {
  background-image: url('https://pic1.imgdb.cn/item/691444cb3203f7be00f8bffa.png') !important;
}

#logo_block .drawer-icon {
  background-image: url('https://pic1.imgdb.cn/item/691445923203f7be00f8c5f7.png') !important;
}

#extensions-settings-button .drawer-icon {
  background-image: url('https://pic1.imgdb.cn/item/691444cb3203f7be00f8bffa.png') !important;
}

#persona-management-button .drawer-icon {
  background-image: url('https://pic1.imgdb.cn/item/691444cb3203f7be00f8bffa.png') !important;
}

#rightNavHolder .drawer-icon {
  background-image: url('https://pic1.imgdb.cn/item/691445923203f7be00f8c5f7.png') !important;
}

#table_drawer_icon {
 background-image: url('https://pic1.imgdb.cn/item/691444cb3203f7be00f8bffa.png') !important;
}


/* 悬停效果 */
#top-settings-holder .drawer-icon:hover::before {
    background: linear-gradient(135deg, #5AA0F2, #3C6F8F);
    -webkit-background-clip: text;
    background-clip: text;
    transform: scale(1.15);
}

/* 展开状态 */
#top-settings-holder .drawer-icon.openIcon::before {
  background: linear-gradient(135deg, #2C5F7F, #1A4A6F);
  -webkit-background-clip: text;
  background-clip: text;
  transform: rotate(180deg);
}

/* ========== 三、底栏 ========== */
#send_form {
  backdrop-filter: blur(15px);
  background-repeat: no-repeat;
  background-size: cover;
  background-position: center;
  border-radius: 0 !important;
  border: 1px solid rgba(74, 144, 226, 0.2) !important;
  box-shadow: 0 -4px 20px rgba(44, 95, 127, 0.15);
}

#send_textarea {
    border-radius: 2px !important;
    clip-path: none !important;
    background-color: rgb(255 255 255 / 71%) !important;
    border: 1px solid rgb(74 144 226 / 10%) !important;
    color: #2C5F7F;
    backdrop-filter: blur(5px);
}

/* 底栏图标样式 */
#send_form [class*="fa-"]::before {
  font-size: 20px;
  vertical-align: middle;
  color: #4A90E2;
  transition: all 0.2s ease;
}

#send_form [class*="fa-"]:hover::before {
  color: #2C5F7F;
  transform: scale(1.1);
}

#mes_stop i::before {
  color: #FF3366 !important;
}

/* ========== 四、聊天区域 ========== */
/* 聊天区域背景透明化 */
#chat {
  -webkit-backdrop-filter: none !important;
  width: 100% !important;
  max-width: 100% !important;
  margin: 0 !important;
  padding: 0 !important;
}

/* 移动端全屏适配 */
@media (max-width: 768px) {
  #chat {
    width: 100vw !important;
    max-width: 100vw !important;
    margin: 0 !important;
    padding: 0 !important;
  }

  .mes {
    width: 100% !important;
    max-width: 100% !important;
    margin-left: 0 !important;
    margin-right: 0 !important;
  }
}

  .mes .mes_block {
    width: 107% !important;
    max-width: 122% !important;
  }

/* 消息气泡核心布局 - 头像嵌入消息框效果 */
.mes {
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
    gap: 0 !important;
    margin-bottom: 30px;
    position: relative;
    width: 100%;
    max-width: 100%;
}

/* 头像包裹容器 */
.mes .mesAvatarWrapper {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0;
    position: relative;
    z-index: 10;
    margin-bottom: -15px; /* 调整为-15px，为三元素留出空间 */
}

/* 头像背景图 - 横版背景 */
.mes .mesAvatarWrapper::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 400px;
  height: 180px;
  background-image: url('https://pic1.imgdb.cn/item/691326913203f7be00f45c57.jpg');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  z-index: 1;
  box-shadow: 0 8px 24px rgba(44, 95, 127, 0.2);
  opacity: 0.95;
  border-radius: 0;
}

/* 头像容器 */
.mes .avatar {
  position: relative;
  overflow: visible !important;
  z-index: 2;
  width: 120px;
  height: 120px;
}

/* 头像图片 - 方形直角 */
.mes .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  border-radius: 0;
  border: 3px solid rgba(255, 255, 255, 0.9);
  box-shadow: 0 4px 16px rgba(44, 95, 127, 0.3);
}

/* 头像框 - 使用指定图片 */
.mes .avatar::after {
  content: '';
  position: absolute;
  top: -70%;
  left: -60%;
  right: -2%;
  bottom: -15%;
  width: 250%;
  height: 250%;
  background-image: url('https://pic1.imgdb.cn/item/6913255a3203f7be00f44ea2.png');
  background-size: contain;
  background-position: center;
  background-repeat: no-repeat;
  pointer-events: none;
  z-index: 3;
}

/* 三元素容器（楼层、计时、词符） */
.mes .avatar-container {
  display: flex;
  gap: 8px;
  align-items: center;
  justify-content: center;
  margin-top: 8px;
  position: relative;
  z-index: 2;
}

.mesIDDisplay,
.mes_timer,
.tokenCounterDisplay {
    position: absolute;
}

.mesIDDisplay {
    top: 135px;
    left: 40px;
    z-index: 21;
    transform: rotate(2deg);
}

.mes_timer {
    top: 145px;
    left: 20px;
    z-index: 21;
    transform: rotate(2deg);
}

.tokenCounterDisplay {
    top: 155px;
    left: 60px;
    z-index: 21;
    transform: rotate(2deg);
}

/* 消息框容器 - 直角设计 */
  .mes .mes_block {
    backdrop-filter: blur(2px) !important;
    background: rgb(255 255 255 / 80%);
    border: 1px solid rgba(74, 144, 226, 0.2);
    border-radius: 0;
    padding: 60px 24px 20px 24px;
    width: 100%;
    max-width: 100%;
    box-shadow: 0 8px 32px rgba(44, 95, 127, 0.15);
    margin-top: 25px;
}

/* AI消息左上角贴图 */
.mes[is_user="false"] .mes_block::after {
  content: '';
  position: absolute;
  top: -160px;
  left: 12px;
  width: 500px;
  height: 500px;
  z-index: 21;
  background-image: url('https://pic1.imgdb.cn/item/69130e7e3203f7be00f36635.png');
  background-size: contain;
  background-repeat: no-repeat;
  opacity: 0.8;
  pointer-events: none;
}

/* 名字文本 */
.mes .name_text {
  font-weight: bold;
  text-shadow: 0 1px 2px rgba(184, 216, 232, 0.5);
  margin-bottom: 8px;
}

/* 消息文本 */
.mes .mes_text {
  padding: 0;
  width: 100%;
  line-height: 1.8;
}

/* 时间戳 */
.mes .timestamp {
  color: #5A6B7C;
  font-size: 0.85em;
  opacity: 0.7;
}

/* 消除最后一条消息大间距 */
.mes.last_mes .mesAvatarWrapper {
    padding-bottom: 0 !important;
}

/* ========== 五、滚动条+滑动条 ========== */
/* 滚动条 */
::-webkit-scrollbar {
    display: none;
}

::-webkit-scrollbar-track {
    background: linear-gradient(180deg, rgba(232, 244, 248, 0.2), rgba(184, 216, 232, 0.2));
    border-radius: 0;
}

::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, #4A90E2, #2C5F7F);
    border-radius: 0;
    border: 2px solid rgba(255, 255, 255, 0.2);
}

::-webkit-scrollbar-thumb:hover {
    background: linear-gradient(180deg, #5AA0F2, #3C6F8F);
}

/* 滑动条 - 按用户要求修改 */
input[type="range"] {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  background: white !important;
  cursor: pointer;
}

/* 滑动条轨道*/
input[type="range"]::-webkit-slider-runnable-track {
  width: 100%;
  height: 6px;
  background:rgb(247 251 255) !important;
  border-radius: 3px;
  border: 1px solid rgba(184, 216, 232, 0.3);
}

input[type="range"] {
  filter:none !important;
}
.neo-range-slider {
  filter:none !important;
}
input:disabled, textarea:disabled {
    cursor: not-allowed;
    filter: none;
}

/* 滑动条手柄 - 使用用户提供的图标 */
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  margin-top:-15px;
  height: 30px;
  width: 30px;
  background-image: url('https://pic1.imgdb.cn/item/69146b223203f7be00f92973.png');
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  background-color: transparent;
  border: none;
  border-radius: 0;
  box-shadow: none;
  transition: transform 0.2s ease;
}

input[type="range"]:hover::-webkit-slider-thumb,
input[type="range"]:active::-webkit-slider-thumb {
  transform: scale(1.2);
}

/* Firefox兼容 */
input[type="range"]::-moz-range-track {
  height: 6px;
  background: rgba(232, 244, 248, 0.6);
  border-radius: 3px;
  border: 1px solid rgba(184, 216, 232, 0.3);
}

input[type="range"]::-moz-range-thumb {
  height: 22px;
  width: 22px;
  background-image: url('https://pic1.imgdb.cn/item/6914653a3203f7be00f91658.png');
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  background-color: transparent;
  border: none;
  border-radius: 0;
}
/* ========== 六、输入框提示文字自定义 ========== */
#send_textarea::placeholder {
  color: transparent;
  opacity: 0;
}

#nonQRFormItems {
  position: relative;
}

#nonQRFormItems::after {
    content: "⋆⁺₊⋆ 𝔐𝔦𝔰𝔱𝔶 𝔟𝔩𝔲𝔢 𝔥𝔞𝔦𝔯 𝔯𝔦𝔟𝔟𝔬𝔫 .･ﾟ☆";
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    color: #93b0e0;
    font-size: 15px;
    font-style: italic;
    pointer-events: none;
    white-space: nowrap;
    z-index: 1;
}

#send_textarea:focus ~ * #nonQRFormItems::after,
#send_textarea:not(:placeholder-shown) ~ * #nonQRFormItems::after,
#nonQRFormItems:has(#send_textarea:focus)::after,
#nonQRFormItems:has(#send_textarea:not(:placeholder-shown))::after {
  display: none;
}
/* ========== 七、正则+脚本易读+防误触 ========== */

.regex-script-label {
    background: #fff;
    /* border: 0px; */
    align-items: baseline;
    border: 1px solid var(--SmartThemeBorderColor);
    border-radius: 0px;
    padding: 0 5px;
    margin-top: 1px;
    margin-bottom: 1px;
}

/* ========== 八、"加载更多消息"美化 ========== */
#show_more_messages {
  background: linear-gradient(135deg, rgba(232, 244, 248, 0.9), rgba(184, 216, 232, 0.8));
  color: #2C5F7F;
  padding: 12px 28px;
  margin: 25px auto;
  border: 1px solid rgba(74, 144, 226, 0.3);
  border-radius: 2px;
  font-weight: bold;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  cursor: pointer;
  transition: all 0.3s ease;
  backdrop-filter: blur(8px);
  box-shadow: 0 4px 16px rgba(44, 95, 127, 0.2);
}

#show_more_messages:hover {
  background: linear-gradient(135deg, rgba(184, 216, 232, 0.95), rgba(74, 144, 226, 0.9));
  color: #E8F4F8;
  transform: translateY(-3px);
  box-shadow: 0 6px 20px rgba(44, 95, 127, 0.3);
}

/* ========== 九、思维链美化 ========== */
.mes_reasoning_summary {
  list-style: none;
  cursor: pointer;
  display: flex !important;
  align-items: center;
}

.mes_reasoning_header {
    background: linear-gradient(135deg, rgba(232, 244, 248, 0.8), rgb(184 216 232 / 6%));
    border: 1px solid rgba(74, 144, 226, 0.3);
    border-radius: 2px;
    /* padding: 10px 18px; */
    transition: all 0.3s ease;
    backdrop-filter: blur(8px);
}

.mes_reasoning_summary:hover .mes_reasoning_header {
  transform: scale(1.03);
  box-shadow: 0 0 12px rgba(74, 144, 226, 0.4);
}

.mes_reasoning_header_title {
  font-size: 0 !important;
}

.mes_reasoning_header_title::before {
    content: '꣑୧ ₊˚ 透明な夢 ⁺ ֯ 𓈒 ';
    font-size: 11px;
    color: #acc6d7;
    font-weight: 100;
}

.mes_reasoning_arrow {
  font-size: 0 !important;
}

.mes_reasoning_arrow::before {
  content: '▶';
  font-size: 12px;
  color: #c5dff1;
  display: inline-block;
  transition: transform 0.3s ease;
}

details[open] .mes_reasoning_arrow::before {
  transform: rotate(90deg);
}

.mes_reasoning {
    margin-top: 8px;
    padding: 16px;
    background: rgb(247 253 255 / 29%);
    border-left: 3px solid #c1d0e0;
    border-radius: 0;
    color: #2C5F7F;
    font-size: 13px;
    line-height: 1.7;
    backdrop-filter: blur(5px);
}

/* ========== 十、收藏栏左右滑动查看角色 ========== */
#HotSwapWrapper {
    overflow: hidden;
}

.hotswap.avatars_inline {
    display: flex;
    flex-wrap: nowrap;
    overflow-x: auto;
    scrollbar-width: thin;
    scrollbar-color: rgba(74, 144, 226, 0.5) rgba(232, 244, 248, 0.3);
    scroll-snap-type: x mandatory;
}

.hotswap.avatars_inline .avatar {
    scroll-snap-align: start;
}

.hotswap.avatars_inline::-webkit-scrollbar {
    height: 6px;
}

.hotswap.avatars_inline::-webkit-scrollbar-track {
    background: rgba(232, 244, 248, 0.3);
    border-radius: 0;
}

.hotswap.avatars_inline::-webkit-scrollbar-thumb {
    background: linear-gradient(to right, #4A90E2, #2C5F7F);
    border-radius: 0;
}

/* ========== 额外优化 ========== */
/* 按钮统一样式 */
button, .menu_button {
  background: linear-gradient(135deg, rgba(232, 244, 248, 0.9), rgba(250, 253, 255, 0.8));
  border: 1px solid rgba(74, 144, 226, 0.3);
  color: #2C5F7F;
  border-radius: 2px;
  transition: all 0.2s ease;
  backdrop-filter: blur(5px);
}

button:hover, .menu_button:hover {
  background: linear-gradient(135deg, rgba(184, 216, 232, 0.95), rgba(74, 144, 226, 0.85));
  color: #E8F4F8;
  box-shadow: 0 4px 12px rgba(44, 95, 127, 0.25);
  transform: translateY(-2px);
}

/* 输入框统一样式 */
input[type="text"],
input[type="number"],
textarea,
select {
  background: rgba(255, 255, 255, 0.8);
  border: 1px solid rgba(74, 144, 226, 0.3);
  color: #2C5F7F;
  border-radius: 2px;
  padding: 8px 12px;
  backdrop-filter: blur(5px);
  transition: all 0.2s ease;
}

input[type="text"]:focus,
input[type="number"]:focus,
textarea:focus,
select:focus {
  border-color: #4A90E2;
  box-shadow: 0 0 0 2px rgba(74, 144, 226, 0.2);
  outline: none;
}

/* 代码块样式 */
.hljs {
    color: #e0e0e0;
    background: none !important; 
}

/* 链接样式 */
a {
  color: #4A90E2;
  text-decoration: none;
  transition: all 0.2s ease;
}

a:hover {
  color: #2C5F7F;
}
/*其他优化*/
.welcomePanel 
    background: #ffffff7d;
}
.welcomeRecent .recentChatList .recentChat {
    border: 2px solid #e6f2f7;
}
.welcomeRecent .recentChatList {
    background: #ffffffa8;
}

/* 5. 紧凑型 UI 调整 */
.character_select,
.group_select,
.tag,
.inline-drawer-toggle,
.extension_button,
.standoutHeader,
button,
.menu_button,
textarea,
select,
#show_more_messages,
.mes_reasoning_header,
.mes_reasoning {
  font-size: 12px !important;
  border-radius: 6px !important;
  margin-top: 4px !important;
  margin-bottom: 4px !important;
}

#extensions_settings .inline-drawer-toggle.inline-drawer-header, #extensions_settings2 .inline-drawer-toggle.inline-drawer-header, #user-settings-block h4, .standoutHeader {
    background-image: none;
}

select option:not(:checked) {
    background-color: #ffffff;
    color: #647b89;
}

select, textarea:not(#send_textarea) {
    background-color: white !important;
    border: 0.5px solid #D2D2D2 !important;
}

/* 提示词字体修复 */
.completion_prompt_manager_header_advanced [data-i18n],
.completion_prompt_manager_header_advanced + div,
.completion_prompt_manager_header_advanced + div > span {
  color: #333 !important;
}

.prompt-manager-inspect-action {
  color: #333 !important;
}
.text_pole {
    background-color: white;
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt .completion_prompt_manager_prompt_name .fa-solid {
    color: #b1c1dd;
}
input[type='checkbox'] {
    background-color: #3883fa29;
    outline:none;
}

.mes em {
    padding: 2px 6px;
    border-radius: 2px;
    background:none !important;
}

.mes q {

    font-size: larger;
    font-weight: 300;
    background: rgb(199 231 247 / 20%);
    padding: 3px 3px;
    border-radius: 0px;
    box-shadow: #e9eef7 2px 2px 2px;
}

pre, code {
    font-weight: 600;
    background: rgba(232, 244, 248, 0.5) !important;
    border: 1px solid rgb(74 144 226 / 24%);
    border-radius: 4px;
    box-shadow: #c7d4e878 4px 3px 4px;
    padding: 2px 8px;
    color: #75b3dc !important;
}

.mes_text blockquote, .mes_reasoning blockquote {
    border-left: 3px solid rgb(187 208 233);
    padding-left: 10px;
    background-color: #f6fafd;
    margin: 0;
}
.drawer-content.openDrawer {
    backdrop-filter: blur(6px) !important;
    background-color: #ffffff80;
    display: block;
    height: auto;
    height: calc-size(auto, size);
    overflow-y: auto;
}
